class ScienceSimulation {
    constructor(container, initialInputs) {
        this.container = container;
        this.canvas = document.createElement('canvas');
        this.ctx = this.canvas.getContext('2d');
        this.container.style.display = 'flex';
        this.container.style.justifyContent = 'center';
        this.container.style.alignItems = 'center';
        this.container.style.background = '#0f172a';
        this.container.appendChild(this.canvas);
        this.resize();
        window.addEventListener('resize', () => this.resize());
    }

    resize() {
        this.canvas.width = this.container.clientWidth;
        this.canvas.height = this.container.clientHeight;
    }

    getSteps(inputs) {
        const n1 = Math.max(10, Math.min(99, Math.floor(inputs.num1)));
        const n2 = Math.max(10, Math.min(99, Math.floor(inputs.num2)));
        const a = Math.floor(n1 / 10), b = n1 % 10;
        const c = Math.floor(n2 / 10), d = n2 % 10;

        const s1 = b * d;
        const carry1 = Math.floor(s1 / 10);
        const s2 = (a * d) + (b * c);
        const s2Total = s2 + carry1;
        const carry2 = Math.floor(s2Total / 10);
        const s3 = (a * c) + carry2;

        return [
            {
                title: "Step 0: Alignment",
                description: "Align the numbers vertically: $ " + n1 + " $ and $ " + n2 + " $. We will calculate the product using the 'Vertically and Crosswise' pattern."
            },
            {
                title: "Step 1: Right Vertical",
                description: "Multiply the units digits: $ " + b + " \\times " + d + " = " + s1 + " $. \\n\\n Write down **" + (s1 % 10) + "** and carry over **" + carry1 + "**."
            },
            {
                title: "Step 2: Crosswise Sum",
                description: "Multiply crosswise and add the carry: $( " + a + " \\times " + d + " ) + ( " + b + " \\times " + c + " ) + \\text{carry } " + carry1 + " = " + (a * d) + " + " + (b * c) + " + " + carry1 + " = " + s2Total + " $. \\n\\n Write down **" + (s2Total % 10) + "** and carry over **" + carry2 + "**."
            },
            {
                title: "Step 3: Left Vertical",
                description: "Multiply the tens digits and add the carry: $( " + a + " \\times " + c + " ) + \\text{carry } " + carry2 + " = " + (a * c) + " + " + carry2 + " = " + s3 + " $. \\n\\n Write down **" + s3 + "**."
            },
            {
                title: "Step 4: Final Result",
                description: "Combining the results from right to left, we get the final product: **" + (n1 * n2) + "**."
            }
        ];
    }

    render(inputs, stepIndex) {
        const ctx = this.ctx;
        const w = this.canvas.width;
        const h = this.canvas.height;
        const n1 = Math.max(10, Math.min(99, Math.floor(inputs.num1)));
        const n2 = Math.max(10, Math.min(99, Math.floor(inputs.num2)));
        const a = Math.floor(n1 / 10), b = n1 % 10;
        const c = Math.floor(n2 / 10), d = n2 % 10;

        ctx.clearRect(0, 0, w, h);

        const centerX = w / 2;
        const centerY = h / 2 - 40;
        const spacing = 80;

        // Draw Digits
        ctx.font = "bold 64px 'Courier New', monospace";
        ctx.textAlign = "center";

        // Number 1
        ctx.fillStyle = "#94a3b8";
        ctx.fillText(a, centerX - spacing/2, centerY);
        ctx.fillText(b, centerX + spacing/2, centerY);

        // Number 2
        ctx.fillText(c, centerX - spacing/2, centerY + spacing);
        ctx.fillText(d, centerX + spacing/2, centerY + spacing);

        // Horizontal Line
        ctx.strokeStyle = "#475569";
        ctx.lineWidth = 4;
        ctx.beginPath();
        ctx.moveTo(centerX - spacing, centerY + spacing + 30);
        ctx.lineTo(centerX + spacing, centerY + spacing + 30);
        ctx.stroke();

        // Pattern Drawing
        ctx.lineWidth = 8;
        ctx.lineCap = "round";

        const s1 = b * d;
        const carry1 = Math.floor(s1 / 10);
        const s2Total = (a * d) + (b * c) + carry1;
        const carry2 = Math.floor(s2Total / 10);
        const s3 = (a * c) + carry2;

        if (stepIndex === 1) {
            this.drawConnection(centerX + spacing/2, centerY, centerX + spacing/2, centerY + spacing, "#3b82f6");
            this.drawResultDigit(s1 % 10, centerX + spacing/2, centerY + spacing + 100, "#3b82f6");
            this.drawCarry(carry1, centerX, centerY + spacing + 60);
        }

        if (stepIndex === 2) {
            this.drawConnection(centerX - spacing/2, centerY, centerX + spacing/2, centerY + spacing, "#3b82f6");
            this.drawConnection(centerX + spacing/2, centerY, centerX - spacing/2, centerY + spacing, "#3b82f6");
            this.drawResultDigit(s2Total % 10, centerX, centerY + spacing + 100, "#3b82f6");
            this.drawCarry(carry2, centerX - spacing/2, centerY + spacing + 60);
        }

        if (stepIndex === 3) {
            this.drawConnection(centerX - spacing/2, centerY, centerX - spacing/2, centerY + spacing, "#3b82f6");
            this.drawResultDigit(s3, centerX - spacing/2, centerY + spacing + 100, "#3b82f6");
        }

        if (stepIndex === 4) {
            ctx.fillStyle = "#10b981";
            ctx.font = "bold 72px 'Courier New', monospace";
            ctx.fillText(n1 * n2, centerX, centerY + spacing + 120);
        }
    }

    drawConnection(x1, y1, x2, y2, color) {
        this.ctx.strokeStyle = color;
        this.ctx.shadowBlur = 15;
        this.ctx.shadowColor = color;
        this.ctx.beginPath();
        this.ctx.moveTo(x1, y1 + 10);
        this.ctx.lineTo(x2, y2 - 40);
        this.ctx.stroke();
        this.ctx.shadowBlur = 0;
    }

    drawResultDigit(val, x, y, color) {
        this.ctx.fillStyle = color;
        this.ctx.font = "bold 48px 'Courier New', monospace";
        this.ctx.fillText(val, x, y);
    }

    drawCarry(val, x, y) {
        if (val === 0) return;
        this.ctx.fillStyle = "#f59e0b";
        this.ctx.font = "bold 24px 'Courier New', monospace";
        this.ctx.fillText("+" + val, x, y);
    }
}
